//! Quality spec ("qspec") — a declared, verifiable acceptance criterion.
//!
//! A qspec is a small JSON contract that asserts "this thing actually works":
//! given a tiny prompt, the model must argmax a specific expected token. It is
//! verified by running a probe binary against a `.knot`; the probe exits 0 iff
//! the expected token is the argmax. Admission (`delegate --qspec`) treats a
//! passing qspec exactly like a validated capability: no proof, no grant.
//!
//! Contract (JSON):
//! ```json
//! { "probe": "paris-probe-rknot",
//!   "knot": "~/.edgework/models/qwen2.5-0.5b-instruct.knot",
//!   "prompt_tokens": [785, 6722, 315, 9625, 374],
//!   "expect_token": 12095, "expect": "Paris" }
//! ```
//! `probe` and `expect` are optional. A leading `~` in `probe`/`knot` expands to
//! `$HOME`. `expect` is a human label only — verification is purely on the token.

use std::collections::HashMap;
use std::path::{Path, PathBuf};
use std::process::Command;

use serde::Deserialize;

const DEFAULT_PROBE: &str = "paris-probe-rknot";
/// How many bytes of the probe's combined stdout/stderr tail to surface on FAIL.
const TAIL_BYTES: usize = 2048;

#[derive(Debug, Clone, Deserialize)]
pub struct QSpec {
    /// Probe binary name or path. Defaults to `paris-probe-rknot`.
    #[serde(default = "default_probe")]
    pub probe: String,
    /// Path to the dense `.knot` model. A leading `~` expands to `$HOME`.
    pub knot: String,
    /// Prompt token ids fed to the probe.
    pub prompt_tokens: Vec<i64>,
    /// The token id the model must argmax for the qspec to pass.
    pub expect_token: i64,
    /// Optional human-readable label for the expected token. Documentation
    /// only — verification is purely on `expect_token`, never this string.
    #[serde(default)]
    #[allow(dead_code)]
    pub expect: Option<String>,
    /// Optional negative control: a token the probe must NOT argmax for the same
    /// prompt. When set, verification ALSO runs the probe expecting this token
    /// and requires it to FAIL. This makes the bad-qspec check declarative: it
    /// proves the probe actually discriminates rather than rubber-stamping
    /// (a phoney always-pass probe, or a model that argmaxes a fixed token,
    /// would pass the reject case and be refused). Must differ from
    /// `expect_token`. Absent ⇒ today's behavior (positive check only).
    #[serde(default)]
    pub reject_token: Option<i64>,
    /// Optional environment variables set on the probe process. Used for
    /// model-specific flags (e.g. `{"GNOSIS_LM_HEAD_FP32": "1"}` for Gemma4).
    #[serde(default)]
    pub env: Option<HashMap<String, String>>,
}

fn default_probe() -> String {
    DEFAULT_PROBE.to_string()
}

/// Expand a leading `~` (or `~/...`) to the user's home directory.
fn expand_tilde(s: &str) -> PathBuf {
    expand_tilde_with(s, std::env::var("HOME").ok().as_deref())
}

/// Tilde expansion against an explicit home, so tests need not mutate `$HOME`.
fn expand_tilde_with(s: &str, home: Option<&str>) -> PathBuf {
    match home {
        Some(home) if s == "~" => PathBuf::from(home),
        Some(home) => match s.strip_prefix("~/") {
            Some(rest) => PathBuf::from(home).join(rest),
            None => PathBuf::from(s),
        },
        None => PathBuf::from(s),
    }
}

impl QSpec {
    /// Parse a qspec from JSON text.
    pub fn parse(text: &str) -> Result<QSpec, String> {
        let spec: QSpec =
            serde_json::from_str(text).map_err(|e| format!("invalid qspec JSON: {e}"))?;
        if spec.prompt_tokens.is_empty() {
            return Err("qspec: prompt_tokens must not be empty".to_string());
        }
        if spec.reject_token == Some(spec.expect_token) {
            return Err(
                "qspec: reject_token must differ from expect_token (a reject equal to \
                 the expected answer is contradictory — the positive and negative \
                 checks could never both hold)"
                    .to_string(),
            );
        }
        Ok(spec)
    }

    /// Load + parse a qspec from a file.
    pub fn load(path: impl AsRef<Path>) -> Result<QSpec, String> {
        let path = path.as_ref();
        let text = std::fs::read_to_string(path)
            .map_err(|e| format!("could not read qspec '{}': {e}", path.display()))?;
        QSpec::parse(&text)
    }

    /// Resolve the probe to an executable path:
    ///   - if `probe` contains '/', expand `~` and use it as a path;
    ///   - else try PATH (via the bare name);
    ///   - else fall back to the distributed-inference release build, at
    ///     `<CARGO_MANIFEST_DIR>/../distributed-inference/target/release/<probe>`.
    pub fn resolve_probe(&self) -> PathBuf {
        if self.probe.contains('/') {
            return expand_tilde(&self.probe);
        }
        // Bare name: prefer PATH if found, otherwise the local release build.
        if which_in_path(&self.probe).is_some() {
            return PathBuf::from(&self.probe);
        }
        let manifest = env!("CARGO_MANIFEST_DIR");
        Path::new(manifest)
            .join("..")
            .join("distributed-inference")
            .join("target")
            .join("release")
            .join(&self.probe)
    }

    /// The argument vector passed to the probe for a given expected token
    /// (knot already tilde-expanded).
    fn probe_args_for(&self, expect: i64) -> Vec<String> {
        let knot = expand_tilde(&self.knot);
        let tokens = self
            .prompt_tokens
            .iter()
            .map(|t| t.to_string())
            .collect::<Vec<_>>()
            .join(",");
        vec![
            "--dense".to_string(),
            knot.to_string_lossy().into_owned(),
            "--dense-only".to_string(),
            "--tokens".to_string(),
            tokens,
            "--expected".to_string(),
            expect.to_string(),
            "--top-k".to_string(),
            "8".to_string(),
        ]
    }

    /// Run the probe expecting `expect`; Ok(()) iff it exits 0 (argmax == expect).
    /// On failure, the Err carries the tail of the probe's combined output.
    fn run_probe(&self, expect: i64) -> Result<(), String> {
        let probe = self.resolve_probe();
        let args = self.probe_args_for(expect);
        let mut cmd = Command::new(&probe);
        cmd.args(&args);
        if let Some(env) = &self.env {
            cmd.envs(env);
        }
        let output = cmd
            .output()
            .map_err(|e| format!("could not run probe '{}': {e}", probe.display()))?;

        if output.status.success() {
            return Ok(());
        }

        let mut combined = String::new();
        combined.push_str(&String::from_utf8_lossy(&output.stdout));
        combined.push_str(&String::from_utf8_lossy(&output.stderr));
        let tail = tail_str(&combined, TAIL_BYTES);
        let code = output
            .status
            .code()
            .map(|c| c.to_string())
            .unwrap_or_else(|| "signal".to_string());
        Err(format!("probe exited {code}; tail:\n{tail}"))
    }

    /// Verify the qspec: the probe must argmax `expect_token` (positive). If a
    /// `reject_token` is declared, the probe must ALSO fail to argmax it for the
    /// same prompt (negative control) — proving the probe discriminates and is
    /// not a rubber-stamp. Both conditions must hold to admit.
    pub fn verify(&self) -> Result<(), String> {
        // Positive: the model must produce the expected token.
        self.run_probe(self.expect_token)?;

        // Negative control (optional): the probe must NOT accept the reject
        // token. If it does, the probe/model does not discriminate — a phoney
        // always-pass probe, or a model argmaxing a fixed token — so refuse.
        if let Some(reject) = self.reject_token {
            if self.run_probe(reject).is_ok() {
                return Err(format!(
                    "qspec self-test FAILED: probe accepted reject_token {reject} for the \
                     same prompt, so it does not discriminate (phoney probe or \
                     fixed-output model). Admission refused."
                ));
            }
        }

        Ok(())
    }
}

/// Verify a qspec file end to end: load, then run the probe.
pub fn verify(path: impl AsRef<Path>) -> Result<(), String> {
    QSpec::load(path)?.verify()
}

/// Last `max_bytes` of a string, on a char boundary, prefixed with `…` if cut.
fn tail_str(s: &str, max_bytes: usize) -> String {
    if s.len() <= max_bytes {
        return s.trim_end().to_string();
    }
    let mut start = s.len() - max_bytes;
    while start < s.len() && !s.is_char_boundary(start) {
        start += 1;
    }
    format!("…{}", s[start..].trim_end())
}

/// Minimal PATH lookup: is `name` an executable somewhere on `$PATH`?
fn which_in_path(name: &str) -> Option<PathBuf> {
    let path = std::env::var_os("PATH")?;
    for dir in std::env::split_paths(&path) {
        let candidate = dir.join(name);
        if is_executable(&candidate) {
            return Some(candidate);
        }
    }
    None
}

fn is_executable(p: &Path) -> bool {
    use std::os::unix::fs::PermissionsExt;
    p.metadata()
        .map(|m| m.is_file() && (m.permissions().mode() & 0o111) != 0)
        .unwrap_or(false)
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::path::PathBuf;

    /// Probe + knot from the reference contract. Tests that need the probe to
    /// actually run are gated on both being present (skip cleanly otherwise),
    /// mirroring the lease tests' style.
    fn reference_knot() -> PathBuf {
        let home = std::env::var("HOME").unwrap_or_default();
        PathBuf::from(home).join(".edgework/models/qwen2.5-0.5b-instruct.knot")
    }

    fn reference_probe() -> PathBuf {
        let manifest = env!("CARGO_MANIFEST_DIR");
        Path::new(manifest)
            .join("..")
            .join("distributed-inference")
            .join("target")
            .join("release")
            .join(DEFAULT_PROBE)
    }

    fn fixtures_present() -> bool {
        reference_knot().exists() && reference_probe().exists()
    }

    fn reference_json(expect_token: i64) -> String {
        format!(
            r#"{{ "probe": "paris-probe-rknot",
                  "knot": "{}",
                  "prompt_tokens": [785,6722,315,9625,374],
                  "expect_token": {expect_token}, "expect": "Paris" }}"#,
            reference_knot().to_string_lossy()
        )
    }

    // ---- pure parser unit test (no probe needed) --------------------------

    #[test]
    fn parses_full_qspec() {
        let spec = QSpec::parse(
            r#"{ "probe": "paris-probe-rknot",
                 "knot": "~/.edgework/models/qwen2.5-0.5b-instruct.knot",
                 "prompt_tokens": [785,6722,315,9625,374],
                 "expect_token": 12095, "expect": "Paris" }"#,
        )
        .unwrap();
        assert_eq!(spec.probe, "paris-probe-rknot");
        assert_eq!(spec.prompt_tokens, vec![785, 6722, 315, 9625, 374]);
        assert_eq!(spec.expect_token, 12095);
        assert_eq!(spec.expect.as_deref(), Some("Paris"));
    }

    #[test]
    fn probe_defaults_when_omitted() {
        let spec = QSpec::parse(
            r#"{ "knot": "/tmp/x.knot", "prompt_tokens": [1,2], "expect_token": 3 }"#,
        )
        .unwrap();
        assert_eq!(spec.probe, DEFAULT_PROBE);
        assert!(spec.expect.is_none());
    }

    #[test]
    fn empty_prompt_tokens_rejected() {
        let err = QSpec::parse(
            r#"{ "knot": "/tmp/x.knot", "prompt_tokens": [], "expect_token": 3 }"#,
        )
        .unwrap_err();
        assert!(err.contains("prompt_tokens"), "got: {err}");
    }

    #[test]
    fn malformed_json_rejected() {
        assert!(QSpec::parse("{ not json").is_err());
    }

    #[test]
    fn tilde_expansion_uses_home() {
        // Uses an explicit home so it never mutates the process-wide $HOME
        // (which the gated probe tests read to locate the knot).
        let home = Some("/home/zzz");
        assert_eq!(
            expand_tilde_with("~/models/a.knot", home),
            PathBuf::from("/home/zzz/models/a.knot")
        );
        assert_eq!(expand_tilde_with("~", home), PathBuf::from("/home/zzz"));
        // Non-tilde paths are passed through verbatim.
        assert_eq!(
            expand_tilde_with("/abs/path", home),
            PathBuf::from("/abs/path")
        );
    }

    #[test]
    fn args_join_tokens_and_carry_flags() {
        let spec = QSpec::parse(
            r#"{ "knot": "/tmp/x.knot", "prompt_tokens": [785,6722,315], "expect_token": 12095 }"#,
        )
        .unwrap();
        let args = spec.probe_args_for(12095);
        assert!(args.contains(&"--dense-only".to_string()));
        assert!(args.windows(2).any(|w| w[0] == "--tokens" && w[1] == "785,6722,315"));
        assert!(args.windows(2).any(|w| w[0] == "--expected" && w[1] == "12095"));
        assert!(args.windows(2).any(|w| w[0] == "--top-k" && w[1] == "8"));
    }

    // ---- gated probe tests (fast, ~2s; skip if fixtures absent) -----------

    #[test]
    fn correct_qspec_verifies() {
        if !fixtures_present() {
            eprintln!("skipping correct_qspec_verifies: 0.5B knot / probe not present");
            return;
        }
        let spec = QSpec::parse(&reference_json(12095)).unwrap();
        assert!(spec.verify().is_ok(), "reference qspec should pass");
    }

    #[test]
    fn wrong_expect_token_is_denied() {
        if !fixtures_present() {
            eprintln!("skipping wrong_expect_token_is_denied: 0.5B knot / probe not present");
            return;
        }
        let spec = QSpec::parse(&reference_json(99999)).unwrap();
        let err = spec.verify().unwrap_err();
        assert!(err.contains("probe exited"), "should carry probe tail: {err}");
    }
}
